import{_ as n,c as i,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"ToS-Warnung: Kontorisiken und Sicherheitspraktiken | Antigravity Auth","description":"Erfahren Sie mehr über die Nutzungsrisiken des Antigravity Auth Plugins und bewährte Sicherheitspraktiken für Ihr Konto. Verstehen Sie Hochrisiko-Szenarien, Shadow-Ban-Mechanismen und Rate-Limiting-Unterschiede. Lernen Sie Multi-Account-Strategien, Nutzungskontrolle und Account-Warming-Methoden.","frontmatter":{"title":"ToS-Warnung: Kontorisiken und Sicherheitspraktiken | Antigravity Auth","sidebarTitle":"Kontosperrung vermeiden","subtitle":"ToS-Warnung: Kontorisiken und Sicherheitspraktiken","description":"Erfahren Sie mehr über die Nutzungsrisiken des Antigravity Auth Plugins und bewährte Sicherheitspraktiken für Ihr Konto. Verstehen Sie Hochrisiko-Szenarien, Shadow-Ban-Mechanismen und Rate-Limiting-Unterschiede. Lernen Sie Multi-Account-Strategien, Nutzungskontrolle und Account-Warming-Methoden.","tags":["FAQ","Risikohinweis","Kontosicherheit"],"prerequisite":["start-quick-install"],"order":5},"headers":[],"relativePath":"de/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md","filePath":"de/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"}'),o={name:"de/NoeFabris/opencode-antigravity-auth/faq/tos-warning/index.md"};function s(a,e,l,u,h,d){return r(),i("div",null,[...e[0]||(e[0]=[t('<h1 id="tos-warnung" tabindex="-1">ToS-Warnung <a class="header-anchor" href="#tos-warnung" aria-label="Permalink to &quot;ToS-Warnung&quot;">​</a></h1><p>Nach diesem Kapitel verstehen Sie die möglichen Risiken bei der Nutzung des Antigravity Auth Plugins und wissen, wie Sie Ihr Google-Konto schützen können.</p><h2 id="ihre-aktuelle-situation" tabindex="-1">Ihre aktuelle Situation <a class="header-anchor" href="#ihre-aktuelle-situation" aria-label="Permalink to &quot;Ihre aktuelle Situation&quot;">​</a></h2><p>Sie erwägen, das Antigravity Auth Plugin zu verwenden, um auf die KI-Modelle von Google Antigravity zuzugreifen, haben aber einige Bedenken:</p><ul><li>Sie haben in der Community Berichte über gesperrte oder shadow-gebannte Konten gesehen</li><li>Sie befürchten, dass die Nutzung inoffizieller Tools gegen Googles Nutzungsbedingungen verstößt</li><li>Sie sind unsicher, ob Sie ein neues oder ein bestehendes Konto verwenden sollten</li><li>Sie möchten wissen, wie Sie das Risiko minimieren können</li></ul><p>Diese Bedenken sind berechtigt. Die Nutzung jedes inoffiziellen Tools birgt gewisse Risiken. Dieser Artikel hilft Ihnen, die konkreten Risikopunkte und Gegenmaßnahmen zu verstehen.</p><h2 id="wann-sie-dieses-kapitel-lesen-sollten" tabindex="-1">Wann Sie dieses Kapitel lesen sollten <a class="header-anchor" href="#wann-sie-dieses-kapitel-lesen-sollten" aria-label="Permalink to &quot;Wann Sie dieses Kapitel lesen sollten&quot;">​</a></h2><ul><li><strong>Vor der Plugin-Installation</strong>: Verstehen Sie die Risiken, bevor Sie sich für die Nutzung entscheiden</li><li><strong>Bei der Kontowahl</strong>: Entscheiden Sie, welches Google-Konto Sie für die Authentifizierung verwenden</li><li><strong>Bei einer Sperrung</strong>: Verstehen Sie mögliche Ursachen und Präventivmaßnahmen</li><li><strong>Bei der Neuregistrierung</strong>: Vermeiden Sie risikoreiche Nutzungsmuster</li></ul><hr><h2 id="uberblick-uber-die-kernrisiken" tabindex="-1">Überblick über die Kernrisiken <a class="header-anchor" href="#uberblick-uber-die-kernrisiken" aria-label="Permalink to &quot;Überblick über die Kernrisiken&quot;">​</a></h2><div class="danger custom-block"><p class="custom-block-title">Wichtige Warnung</p><p><strong>Die Nutzung dieses Plugins kann gegen Googles Nutzungsbedingungen (Terms of Service) verstoßen.</strong></p><p>Einige Nutzer haben berichtet, dass ihre Google-Konten gesperrt oder shadow-gebannt wurden (Shadow Ban bedeutet eingeschränkter Zugriff ohne explizite Benachrichtigung).</p><p><strong>Mit der Nutzung dieses Plugins akzeptieren Sie folgende Erklärung:</strong></p><ol><li>Dies ist ein inoffizielles Tool, das nicht von Google genehmigt oder unterstützt wird</li><li>Ihr Google-Konto kann vorübergehend oder dauerhaft gesperrt werden</li><li>Sie tragen alle Risiken und Konsequenzen der Nutzung dieses Plugins selbst</li></ol></div><h3 id="was-ist-ein-shadow-ban" tabindex="-1">Was ist ein Shadow Ban? <a class="header-anchor" href="#was-ist-ein-shadow-ban" aria-label="Permalink to &quot;Was ist ein Shadow Ban?&quot;">​</a></h3><p><strong>Shadow Ban</strong> ist eine Einschränkungsmaßnahme, die Google bei verdächtigen Konten anwendet. Im Gegensatz zu einer direkten Sperrung zeigt ein Shadow Ban keine eindeutige Fehlermeldung an, sondern:</p><ul><li>API-Anfragen geben 403- oder 429-Fehler zurück</li><li>Das Kontingent wird als verfügbar angezeigt, aber Aufrufe sind tatsächlich nicht möglich</li><li>Andere Konten funktionieren normal, nur das markierte Konto ist betroffen</li></ul><p>Ein Shadow Ban dauert in der Regel länger (Tage bis Wochen) und kann nicht durch Einspruch aufgehoben werden.</p><hr><h2 id="hochrisiko-szenarien" tabindex="-1">Hochrisiko-Szenarien <a class="header-anchor" href="#hochrisiko-szenarien" aria-label="Permalink to &quot;Hochrisiko-Szenarien&quot;">​</a></h2><p>Die folgenden Szenarien erhöhen das Risiko einer Markierung oder Sperrung Ihres Kontos erheblich:</p><h3 id="🚨-szenario-1-brandneues-google-konto" tabindex="-1">🚨 Szenario 1: Brandneues Google-Konto <a class="header-anchor" href="#🚨-szenario-1-brandneues-google-konto" aria-label="Permalink to &quot;🚨 Szenario 1: Brandneues Google-Konto&quot;">​</a></h3><p><strong>Risikostufe: Sehr hoch</strong></p><p>Die Wahrscheinlichkeit einer Sperrung ist bei neu registrierten Google-Konten, die dieses Plugin nutzen, sehr hoch. Gründe:</p><ul><li>Neue Konten haben keine historischen Verhaltensdaten und werden leicht vom Missbrauchserkennungssystem von Google markiert</li><li>Viele API-Aufrufe auf neuen Konten werden als abnormales Verhalten angesehen</li><li>Google prüft neue Konten strenger</li></ul><p><strong>Empfehlung</strong>: Erstellen Sie kein neues Konto speziell für dieses Plugin.</p><h3 id="🚨-szenario-2-neues-konto-pro-ultra-abonnement" tabindex="-1">🚨 Szenario 2: Neues Konto + Pro/Ultra-Abonnement <a class="header-anchor" href="#🚨-szenario-2-neues-konto-pro-ultra-abonnement" aria-label="Permalink to &quot;🚨 Szenario 2: Neues Konto + Pro/Ultra-Abonnement&quot;">​</a></h3><p><strong>Risikostufe: Sehr hoch</strong></p><p>Neu registrierte Konten, die sofort ein Pro- oder Ultra-Abonnement von Google abschließen, werden häufig markiert und gesperrt. Gründe:</p><ul><li>Das hohe Nutzungsmuster nach dem Abonnement sieht bei neuen Konten wie Missbrauch aus</li><li>Google prüft neue zahlende Nutzer strenger</li><li>Dieses Muster weicht zu stark vom normalen Wachstumspfad eines Nutzers ab</li></ul><p><strong>Empfehlung</strong>: Lassen Sie das Konto erst eine Weile „natürlich wachsen&quot; (mindestens einige Monate), bevor Sie ein Abonnement in Betracht ziehen.</p><h3 id="🟡-szenario-3-viele-anfragen-in-kurzer-zeit" tabindex="-1">🟡 Szenario 3: Viele Anfragen in kurzer Zeit <a class="header-anchor" href="#🟡-szenario-3-viele-anfragen-in-kurzer-zeit" aria-label="Permalink to &quot;🟡 Szenario 3: Viele Anfragen in kurzer Zeit&quot;">​</a></h3><p><strong>Risikostufe: Hoch</strong></p><p>Das Senden vieler API-Anfragen in kurzer Zeit oder die häufige Nutzung von parallelen Proxys/Multi-Sessions löst Rate-Limiting und Missbrauchserkennung aus. Gründe:</p><ul><li>Das Anfragemuster von OpenCode ist intensiver als bei nativen Anwendungen (Tool-Aufrufe, Wiederholungen, Streaming usw.)</li><li>Hochkonkurrente Anfragen lösen Googles Schutzmechanismen aus</li></ul><p><strong>Empfehlungen</strong>:</p><ul><li>Kontrollieren Sie die Anfragehäufigkeit und Parallelität</li><li>Vermeiden Sie das gleichzeitige Starten mehrerer paralleler Agenten</li><li>Verwenden Sie Multi-Account-Rotation zur Verteilung der Anfragen</li></ul><h3 id="🟡-szenario-4-nutzung-eines-einzigen-google-kontos" tabindex="-1">🟡 Szenario 4: Nutzung eines einzigen Google-Kontos <a class="header-anchor" href="#🟡-szenario-4-nutzung-eines-einzigen-google-kontos" aria-label="Permalink to &quot;🟡 Szenario 4: Nutzung eines einzigen Google-Kontos&quot;">​</a></h3><p><strong>Risikostufe: Mittel</strong></p><p>Wenn Sie nur ein Google-Konto haben und für wichtige Dienste (Gmail, Drive usw.) darauf angewiesen sind, ist das Risiko höher. Gründe:</p><ul><li>Eine Kontosperrung beeinträchtigt Ihre tägliche Arbeit</li><li>Keine Wiederherstellung durch Einspruch möglich</li><li>Keine Backup-Lösung vorhanden</li></ul><p><strong>Empfehlung</strong>: Verwenden Sie ein separates Konto, das nicht von wichtigen Diensten abhängt.</p><hr><h2 id="best-practice-empfehlungen" tabindex="-1">Best-Practice-Empfehlungen <a class="header-anchor" href="#best-practice-empfehlungen" aria-label="Permalink to &quot;Best-Practice-Empfehlungen&quot;">​</a></h2><h3 id="✅-empfohlene-vorgehensweisen" tabindex="-1">✅ Empfohlene Vorgehensweisen <a class="header-anchor" href="#✅-empfohlene-vorgehensweisen" aria-label="Permalink to &quot;✅ Empfohlene Vorgehensweisen&quot;">​</a></h3><p><strong>1. Verwenden Sie ein etabliertes Google-Konto</strong></p><p>Bevorzugen Sie ein Google-Konto, das bereits eine Weile genutzt wird (empfohlen: mindestens 6 Monate):</p><ul><li>Hat eine normale Nutzungshistorie von Google-Diensten (Gmail, Drive, Google Search usw.)</li><li>Keine früheren Verstöße</li><li>Konto ist mit einer Telefonnummer verknüpft und verifiziert</li></ul><p><strong>2. Konfigurieren Sie mehrere Konten</strong></p><p>Fügen Sie mehrere Google-Konten hinzu und verteilen Sie Anfragen durch Rotation:</p><ul><li>Konfigurieren Sie mindestens 2-3 Konten</li><li>Verwenden Sie die Strategie <code>account_selection_strategy: &quot;hybrid&quot;</code> (Standard)</li><li>Automatischer Kontowechsel bei Rate-Limiting</li></ul><p><strong>3. Kontrollieren Sie die Nutzung</strong></p><ul><li>Vermeiden Sie intensive Anfragen in kurzer Zeit</li><li>Reduzieren Sie die Anzahl paralleler Agenten</li><li>Setzen Sie in <code>antigravity.json</code> <code>max_rate_limit_wait_seconds: 0</code> für schnelles Scheitern statt Wiederholung</li></ul><p><strong>4. Überwachen Sie den Kontostatus</strong></p><p>Überprüfen Sie regelmäßig den Kontostatus:</p><ul><li>Prüfen Sie <code>rateLimitResetTimes</code> in <code>~/.config/opencode/antigravity-accounts.json</code></li><li>Aktivieren Sie Debug-Logging: <code>OPENCODE_ANTIGRAVITY_DEBUG=1 opencode</code></li><li>Pausieren Sie die Nutzung für 24-48 Stunden bei 403/429-Fehlern</li></ul><p><strong>5. Erst in der offiziellen Oberfläche „aufwärmen&quot;</strong></p><p>Von Community-Nutzern berichtete effektive Methode:</p><ol><li>Melden Sie sich im Browser bei <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a> an</li><li>Führen Sie einige einfache Prompts aus (z.B. „Hallo&quot;, „Was ist 2+2&quot;)</li><li>Nach 5-10 erfolgreichen Aufrufen können Sie das Plugin verwenden</li></ol><p><strong>Prinzip</strong>: Die Nutzung des Kontos über die offizielle Oberfläche lässt Google glauben, dass es sich um normales Nutzerverhalten handelt, was das Risiko einer Markierung verringert.</p><h3 id="❌-zu-vermeidende-vorgehensweisen" tabindex="-1">❌ Zu vermeidende Vorgehensweisen <a class="header-anchor" href="#❌-zu-vermeidende-vorgehensweisen" aria-label="Permalink to &quot;❌ Zu vermeidende Vorgehensweisen&quot;">​</a></h3><ul><li>❌ Erstellen Sie kein brandneues Google-Konto speziell für dieses Plugin</li><li>❌ Abonnieren Sie nicht sofort Pro/Ultra auf einem neu registrierten Konto</li><li>❌ Verwenden Sie nicht Ihr einziges Konto für wichtige Dienste (z.B. Arbeits-E-Mail)</li><li>❌ Wiederholen Sie nicht ständig nach einem 429-Limit</li><li>❌ Starten Sie nicht viele parallele Agenten gleichzeitig</li><li>❌ Committen Sie <code>antigravity-accounts.json</code> nicht in die Versionskontrolle</li></ul><hr><h2 id="haufig-gestellte-fragen" tabindex="-1">Häufig gestellte Fragen <a class="header-anchor" href="#haufig-gestellte-fragen" aria-label="Permalink to &quot;Häufig gestellte Fragen&quot;">​</a></h2><h3 id="f-mein-konto-wurde-gesperrt-kann-ich-einspruch-einlegen" tabindex="-1">F: Mein Konto wurde gesperrt, kann ich Einspruch einlegen? <a class="header-anchor" href="#f-mein-konto-wurde-gesperrt-kann-ich-einspruch-einlegen" aria-label="Permalink to &quot;F: Mein Konto wurde gesperrt, kann ich Einspruch einlegen?&quot;">​</a></h3><p><strong>A: Nein.</strong></p><p>Wenn die Sperrung oder der Shadow Ban durch die Missbrauchserkennung von Google aufgrund dieses Plugins ausgelöst wurde, ist eine Wiederherstellung durch Einspruch in der Regel nicht möglich. Gründe:</p><ul><li>Die Sperrung wird automatisch basierend auf API-Nutzungsmustern ausgelöst</li><li>Google hat eine strenge Haltung gegenüber der Nutzung inoffizieller Tools</li><li>Bei einem Einspruch müssten Sie den Verwendungszweck des Tools erklären, aber dieses Plugin selbst könnte als Verstoß angesehen werden</li></ul><p><strong>Empfehlungen</strong>:</p><ul><li>Verwenden Sie andere nicht betroffene Konten</li><li>Wenn alle Konten gesperrt sind, nutzen Sie direkt <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a></li><li>Vermeiden Sie weitere Versuche auf dem gesperrten Konto</li></ul><h3 id="f-wird-mein-konto-bei-nutzung-dieses-plugins-definitiv-gesperrt" tabindex="-1">F: Wird mein Konto bei Nutzung dieses Plugins definitiv gesperrt? <a class="header-anchor" href="#f-wird-mein-konto-bei-nutzung-dieses-plugins-definitiv-gesperrt" aria-label="Permalink to &quot;F: Wird mein Konto bei Nutzung dieses Plugins definitiv gesperrt?&quot;">​</a></h3><p><strong>A: Nicht unbedingt.</strong></p><p>Die meisten Nutzer haben bei der Verwendung dieses Plugins keine Probleme. Das Risiko hängt ab von:</p><ul><li>Kontoalter und historischem Verhalten</li><li>Nutzungshäufigkeit und Anfragemuster</li><li>Einhaltung der Best Practices</li></ul><p><strong>Risikobewertung</strong>:</p><ul><li>Altes Konto + moderate Nutzung + Multi-Account-Rotation → Niedriges Risiko</li><li>Neues Konto + intensive Anfragen + Einzelkonto → Hohes Risiko</li></ul><h3 id="f-was-ist-der-unterschied-zwischen-shadow-ban-und-rate-limiting" tabindex="-1">F: Was ist der Unterschied zwischen Shadow Ban und Rate-Limiting? <a class="header-anchor" href="#f-was-ist-der-unterschied-zwischen-shadow-ban-und-rate-limiting" aria-label="Permalink to &quot;F: Was ist der Unterschied zwischen Shadow Ban und Rate-Limiting?&quot;">​</a></h3><p><strong>A: Grundlegend unterschiedlich, auch die Wiederherstellungsmethoden.</strong></p><table tabindex="0"><thead><tr><th>Merkmal</th><th>Shadow Ban</th><th>Rate-Limiting (429)</th></tr></thead><tbody><tr><td>Auslöser</td><td>Missbrauchserkennung, als verdächtig markiert</td><td>Anfragehäufigkeit überschreitet Kontingent</td></tr><tr><td>Fehlercode</td><td>403 oder stilles Scheitern</td><td>429 Too Many Requests</td></tr><tr><td>Dauer</td><td>Tage bis Wochen</td><td>Stunden bis ein Tag</td></tr><tr><td>Wiederherstellung</td><td>Nicht möglich, anderes Konto erforderlich</td><td>Warten auf Reset oder Kontowechsel</td></tr><tr><td>Vermeidbar</td><td>Best Practices befolgen reduziert Risiko</td><td>Anfragehäufigkeit kontrollieren</td></tr></tbody></table><h3 id="f-kann-ich-ein-unternehmens-google-konto-verwenden" tabindex="-1">F: Kann ich ein Unternehmens-Google-Konto verwenden? <a class="header-anchor" href="#f-kann-ich-ein-unternehmens-google-konto-verwenden" aria-label="Permalink to &quot;F: Kann ich ein Unternehmens-Google-Konto verwenden?&quot;">​</a></h3><p><strong>A: Nicht empfohlen.</strong></p><p>Unternehmenskonten sind in der Regel mit wichtigen Diensten und Daten verknüpft, eine Sperrung hat schwerwiegendere Auswirkungen. Außerdem:</p><ul><li>Unternehmenskonten werden strenger geprüft</li><li>Könnte gegen die IT-Richtlinien des Unternehmens verstoßen</li><li>Das Risiko trägt die Einzelperson, aber es betrifft das Team</li></ul><p><strong>Empfehlung</strong>: Verwenden Sie ein persönliches Konto.</p><h3 id="f-konnen-mehrere-konten-eine-sperrung-vollstandig-verhindern" tabindex="-1">F: Können mehrere Konten eine Sperrung vollständig verhindern? <a class="header-anchor" href="#f-konnen-mehrere-konten-eine-sperrung-vollstandig-verhindern" aria-label="Permalink to &quot;F: Können mehrere Konten eine Sperrung vollständig verhindern?&quot;">​</a></h3><p><strong>A: Nicht vollständig, aber sie können die Auswirkungen reduzieren.</strong></p><p>Vorteile mehrerer Konten:</p><ul><li>Verteilung der Anfragen, geringere Wahrscheinlichkeit, dass ein einzelnes Konto Limits auslöst</li><li>Wenn ein Konto gesperrt wird, sind andere Konten weiterhin verfügbar</li><li>Automatischer Wechsel bei Limits, höhere Verfügbarkeit</li></ul><p><strong>Aber mehrere Konten sind kein „Schutzschild&quot;</strong>:</p><ul><li>Wenn alle Konten die Missbrauchserkennung auslösen, können alle gesperrt werden</li><li>Missbrauchen Sie nicht mehrere Konten für intensive Anfragen</li><li>Jedes Konto muss weiterhin den Best Practices folgen</li></ul><hr><h2 id="checkliste-✅" tabindex="-1">Checkliste ✅ <a class="header-anchor" href="#checkliste-✅" aria-label="Permalink to &quot;Checkliste ✅&quot;">​</a></h2><p>Nach diesem Kapitel sollten Sie wissen:</p><ul><li>[ ] Die Nutzung dieses Plugins kann gegen Googles ToS verstoßen, auf eigenes Risiko</li><li>[ ] Neues Konto + Pro/Ultra-Abonnement ist ein Hochrisiko-Szenario</li><li>[ ] Empfohlen wird die Verwendung eines etablierten Google-Kontos</li><li>[ ] Die Konfiguration mehrerer Konten kann das Risiko verteilen</li><li>[ ] Nach einer Kontosperrung ist keine Wiederherstellung durch Einspruch möglich</li><li>[ ] Die Kontrolle von Anfragehäufigkeit und Nutzung ist wichtig</li></ul><hr><h2 id="zusammenfassung" tabindex="-1">Zusammenfassung <a class="header-anchor" href="#zusammenfassung" aria-label="Permalink to &quot;Zusammenfassung&quot;">​</a></h2><p>Dieses Kapitel hat die möglichen Risiken bei der Nutzung des Antigravity Auth Plugins vorgestellt:</p><ol><li><strong>Kernrisiken</strong>: Möglicher Verstoß gegen Googles ToS, Konto kann gesperrt oder shadow-gebannt werden</li><li><strong>Hochrisiko-Szenarien</strong>: Neues Konto, neues Konto + Abonnement, intensive Anfragen, einzelnes wichtiges Konto</li><li><strong>Best Practices</strong>: Altes Konto verwenden, mehrere Konten konfigurieren, Nutzung kontrollieren, Status überwachen, erst „aufwärmen&quot;</li><li><strong>Häufige Fragen</strong>: Kein Einspruch möglich, Risiko variiert individuell, mehrere Konten können Auswirkungen reduzieren</li></ol><p>Bitte bewerten Sie die Risiken sorgfältig, bevor Sie dieses Plugin verwenden. Wenn Sie die möglichen Konsequenzen einer Kontosperrung nicht akzeptieren können, empfehlen wir die direkte Nutzung von <a href="https://idx.google.com/" target="_blank" rel="noreferrer">Antigravity IDE</a>.</p><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken Sie hier, um die Quellcode-Positionen anzuzeigen</strong></summary><blockquote><p>Aktualisiert: 2026-01-23</p></blockquote><p>Der Inhalt dieses Kapitels basiert auf dem Risikowarnungsabschnitt der Projekt-README-Dokumentation (README.md:23-40) und beinhaltet keine spezifische Code-Implementierung.</p><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilen</th></tr></thead><tbody><tr><td>ToS-Warnungshinweis</td><td><a href="https://github.com/NoeFabris/opencode-antigravity-auth/blob/main/README.md#L23-L40" target="_blank" rel="noreferrer"><code>README.md</code></a></td><td>23-40</td></tr></tbody></table></details>',99)])])}const m=n(o,[["render",s]]);export{c as __pageData,m as default};
